26	func (s *CollectibleService) Create(ctx context.Context, req dto.CreateCollectibleRequest, sellerID uuid.UUID) (*model.Collectible, error) {
27		currency := req.Currency
28		if currency == "" {
29			currency = "USD"
30		}
31	
32		tokenID := req.TokenID
33		chainID := req.ChainID
34		hasToken := tokenID != ""
35		hasChain := chainID != 0
36		if req.ContractAddress != "" {
37			if !hasToken || !hasChain {
38				return nil, fmt.Errorf("%w: contract_address requires chain_id and token_id", dto.ErrValidation)
39			}
40		} else if hasToken || hasChain {
41			// When either identity field is provided, require both.
42			if !hasToken || !hasChain {
43				return nil, fmt.Errorf("%w: chain_id and token_id must both be provided when either is set", dto.ErrValidation)
44			}
45		} else {
46			// Neither provided — generate platform defaults for off-chain items.
47			tokenID = uuid.New().String()
48			chainID = 1
49		}
50	
51		c := &model.Collectible{
52			SellerID:        sellerID,
53			Title:           req.Title,
54			Description:     req.Description,
55			ContractAddress: req.ContractAddress,
56			ChainID:         chainID,
57			TokenID:         tokenID,
58			MetadataURI:     req.MetadataURI,
59			ImageURL:        req.ImageURL,
60			PriceCents:      req.PriceCents,
61			Currency:        currency,
62		}
63	
64		if err := s.collectibleStore.Create(ctx, c); err != nil {
65			if strings.Contains(err.Error(), "idx_collectibles_identity") || strings.Contains(err.Error(), "duplicate key") {
66				return nil, fmt.Errorf("%w: a collectible with this contract_address, chain_id, and token_id already exists", dto.ErrConflict)
67			}
68			return nil, fmt.Errorf("create collectible: %w", err)
69		}
70		s.invalidateCache()
71		return c, nil
72	}
73	
74	// GetByID returns a collectible. Hidden collectibles are only visible to admin/compliance roles.
75	func (s *CollectibleService) GetByID(ctx context.Context, id uuid.UUID, viewerRoles []string) (*model.Collectible, error) {
76		cacheKey := "collectible:" + id.String()
77		if cached, ok := s.cache.Get(cacheKey); ok {
78			c := cached.(*model.Collectible)
79			if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
80				return nil, dto.ErrNotFound
81			}
82			return c, nil
83		}
84	
85		c, err := s.collectibleStore.GetByID(ctx, id)
86		if err != nil {
87			return nil, err
88		}
89		if c == nil {
90			return nil, dto.ErrNotFound
91		}
92	
93		// Hidden collectibles only visible to admin/compliance
94		if c.Status == "hidden" && !hasAdminOrCompliance(viewerRoles) {
95			return nil, dto.ErrNotFound
96		}
97	
98		s.cache.Set(cacheKey, c, 2*time.Minute)
99	
100		// Emit item_view event and increment view count async
101		go func() {
102			_ = s.collectibleStore.IncrementViewCount(context.Background(), id)
103		}()
104	
105		return c, nil
106	}
107	
108	// EmitViewEvent emits an analytics event for viewing. Called separately to have access to userID.
109	func (s *CollectibleService) EmitViewEvent(ctx context.Context, userID *uuid.UUID, collectibleID uuid.UUID) {
110		if s.analyticsStore == nil {
111			return
112		}
113		abVariant := resolveABVariant(s.analyticsStore, userID)
114		go func() {
115			_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
116				UserID:        userID,
117				EventType:     "item_view",
118				CollectibleID: &collectibleID,
119				SessionID:     "server",
120				ABVariant:     abVariant,
121			})
122		}()
123	}
124	
125	// List returns collectibles. Non-admin users can only see published.
126	func (s *CollectibleService) List(ctx context.Context, status string, page, pageSize int, viewerRoles []string, userID *uuid.UUID) ([]model.Collectible, int, error) {
127		// Non-admin/compliance users can ONLY see published
128		if !hasAdminOrCompliance(viewerRoles) {
129			status = "published"
130		}
131	
132		cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
133		if cached, ok := s.cache.Get(cacheKey); ok {
134			result := cached.(*cachedList)
135			return result.items, result.total, nil
136		}
137	
138		items, total, err := s.collectibleStore.List(ctx, status, page, pageSize)
139		if err != nil {
140			return nil, 0, err
141		}
142	
143		s.cache.Set(cacheKey, &cachedList{items: items, total: total}, 30*time.Second)
144	
145		// Emit catalog_view event async with A/B variant tagging
146		if s.analyticsStore != nil {
147			abVariant := resolveABVariant(s.analyticsStore, userID)
148			go func() {
149				_ = s.analyticsStore.RecordEvent(context.Background(), &model.AnalyticsEvent{
150					UserID:    userID,
151					EventType: "catalog_view",
152					SessionID: "server",
153					ABVariant: abVariant,
154				})
155			}()
156		}
157	
158		return items, total, nil
159	}
160	
161	type cachedList struct {
162		items []model.Collectible
163		total int
164	}
165	
166	func (s *CollectibleService) ListBySeller(ctx context.Context, sellerID uuid.UUID, page, pageSize int) ([]model.Collectible, int, error) {
