170	func (s *CollectibleService) Update(ctx context.Context, id uuid.UUID, req dto.UpdateCollectibleRequest, actorID uuid.UUID) (*model.Collectible, error) {
171		c, err := s.collectibleStore.GetByID(ctx, id)
172		if err != nil {
173			return nil, err
174		}
175		if c == nil {
176			return nil, dto.ErrNotFound
177		}
178		if c.SellerID != actorID {
179			return nil, dto.ErrForbidden
180		}
181	
182		if req.Title != nil {
183			c.Title = *req.Title
184		}
185		if req.Description != nil {
186			c.Description = *req.Description
187		}
188		if req.PriceCents != nil {
189			c.PriceCents = *req.PriceCents
190		}
191		if req.ImageURL != nil {
192			c.ImageURL = *req.ImageURL
193		}
194		if req.MetadataURI != nil {
195			c.MetadataURI = *req.MetadataURI
196		}
197	
198		if err := s.collectibleStore.Update(ctx, c); err != nil {
199			return nil, fmt.Errorf("update collectible: %w", err)
200		}
201		s.invalidateCache()
202		return c, nil
203	}
