15	type OrderService struct {
16		orderStore       *store.OrderStore
17		collectibleStore *store.CollectibleStore
18		notifService     *NotificationService
19		analyticsStore   *store.AnalyticsStore
20	}
21	
22	func NewOrderService(os *store.OrderStore, cs *store.CollectibleStore, ns *NotificationService, as *store.AnalyticsStore) *OrderService {
23		return &OrderService{orderStore: os, collectibleStore: cs, notifService: ns, analyticsStore: as}
24	}
25	
26	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
27		existing, err := s.orderStore.GetByIdempotencyKey(ctx, buyerID, idempotencyKey)
28		if err != nil {
29			return nil, fmt.Errorf("check idempotency: %w", err)
30		}
31		if existing != nil {
32			return existing, nil
33		}
34	
35		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
36		if err != nil {
37			return nil, fmt.Errorf("get collectible: %w", err)
38		}
39		if collectible == nil {
40			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
41			return nil, dto.ErrNotFound
42		}
43		if collectible.Status != "published" {
44			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
45			return nil, dto.ErrNotFound
46		}
47		if collectible.SellerID == buyerID {
48			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
49			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
50		}
51	
52		tx, err := s.orderStore.BeginTx(ctx)
53		if err != nil {
54			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
55			return nil, fmt.Errorf("begin tx: %w", err)
56		}
57		defer tx.Rollback(ctx)
58	
59		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
60			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
61			return nil, fmt.Errorf("acquire lock: %w", err)
62		}
63	
64		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
65		if err != nil {
66			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
67			return nil, fmt.Errorf("check active orders: %w", err)
68		}
69		if hasActive {
70			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
71			return nil, dto.ErrOversold
72		}
73	
74		order := &model.Order{
75			IdempotencyKey:     idempotencyKey,
76			BuyerID:            buyerID,
77			CollectibleID:      req.CollectibleID,
78			SellerID:           collectible.SellerID,
79			Status:             model.OrderStatusPending,
80			PriceSnapshotCents: collectible.PriceCents,
81		}
82	
83		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
84			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
85			return nil, fmt.Errorf("create order: %w", err)
86		}
87	
88		transition := &model.OrderStateTransition{
89			OrderID:    order.ID,
90			FromStatus: "",
91			ToStatus:   model.OrderStatusPending,
92			ActorID:    buyerID,
93			Reason:     "order created",
94		}
95		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
96			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
97			return nil, fmt.Errorf("record transition: %w", err)
98		}
99	
100		if err := tx.Commit(ctx); err != nil {
101			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
102			return nil, fmt.Errorf("commit: %w", err)
103		}
104	
105		// Emit analytics event
106		s.emitEvent(ctx, &buyerID, "order_created", &req.CollectibleID)
107	
108		return order, nil
109	}
