12	
13	type Config struct {
14		ListenAddr    string
15		DatabaseURL   string
16		JWTSigningKey []byte
17		AESMasterKey  []byte
18	}
19	
20	type secretsFile struct {
21		DatabaseURL   string `json:"database_url"`
22		JWTSigningKey string `json:"jwt_signing_key"`
23		AESMasterKey  string `json:"aes_master_key"`
24	}
25	
26	func Load() (*Config, error) {
27		listenAddr := os.Getenv("LISTEN_ADDR")
28		if listenAddr == "" {
29			listenAddr = ":8080"
30		}
31	
32		keyfile := os.Getenv("SECRETS_KEYFILE")
33		if keyfile != "" {
34			return loadFromKeyfile(listenAddr, keyfile)
35		}
36	
37		// Plaintext env vars only allowed in explicit development mode.
38		// When APP_ENV is empty the system assumes development for backward
39		// compatibility, but any other value (staging, production, etc.)
40		// requires an encrypted keyfile.
41		appEnv := os.Getenv("APP_ENV")
42		if appEnv != "" && appEnv != "development" {
43			return nil, fmt.Errorf("SECRETS_KEYFILE is required when APP_ENV=%s; plaintext env vars are only allowed when APP_ENV is unset or set to 'development'", appEnv)
44		}
45	
46		return loadFromEnv(listenAddr)
47	}
48	
49	func loadFromEnv(listenAddr string) (*Config, error) {
50		dbURL := os.Getenv("DATABASE_URL")
51		if dbURL == "" {
52			return nil, fmt.Errorf("DATABASE_URL is required")
53		}
54	
55		jwtKey := os.Getenv("JWT_SIGNING_KEY")
56		if jwtKey == "" {
57			return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
58		}
59	
60		aesKey, err := decodeAESKey(os.Getenv("AES_MASTER_KEY"))
61		if err != nil {
62			return nil, err
63		}
64	
65		return &Config{
66			ListenAddr:    listenAddr,
67			DatabaseURL:   dbURL,
68			JWTSigningKey: []byte(jwtKey),
69			AESMasterKey:  aesKey,
70		}, nil
71	}
72	
73	func loadFromKeyfile(listenAddr, path string) (*Config, error) {
74		passphrase := os.Getenv("SECRETS_PASSPHRASE")
75		if passphrase == "" {
76			return nil, fmt.Errorf("SECRETS_PASSPHRASE is required when using SECRETS_KEYFILE")
77		}
78	
79		// Validate keyfile permissions: reject world-readable or group-readable files.
80		info, err := os.Stat(path)
81		if err != nil {
82			return nil, fmt.Errorf("stat keyfile %s: %w", path, err)
83		}
84		if mode := info.Mode().Perm(); mode&0o077 != 0 {
85			return nil, fmt.Errorf("keyfile %s has insecure permissions %04o; must be owner-only (0600)", path, mode)
86		}
87	
88		ciphertext, err := os.ReadFile(path)
89		if err != nil {
90			return nil, fmt.Errorf("read keyfile %s: %w", path, err)
91		}
92	
93		plaintext, err := decryptKeyfile(ciphertext, passphrase)
94		if err != nil {
95			return nil, fmt.Errorf("decrypt keyfile: %w", err)
96		}
97	
98		var secrets secretsFile
99		if err := json.Unmarshal(plaintext, &secrets); err != nil {
100			return nil, fmt.Errorf("parse keyfile JSON: %w", err)
101		}
102	
103		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
104			return nil, fmt.Errorf("keyfile must contain database_url, jwt_signing_key, and aes_master_key")
105		}
106	
107		aesKey, err := decodeAESKey(secrets.AESMasterKey)
108		if err != nil {
109			return nil, err
110		}
111	
112		return &Config{
113			ListenAddr:    listenAddr,
114			DatabaseURL:   secrets.DatabaseURL,
115			JWTSigningKey: []byte(secrets.JWTSigningKey),
116			AESMasterKey:  aesKey,
117		}, nil
118	}
119	
120	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
121		key := sha256.Sum256([]byte(passphrase))
122		block, err := aes.NewCipher(key[:])
123		if err != nil {
124			return nil, err
125		}
126		gcm, err := cipher.NewGCM(block)
127		if err != nil {
128			return nil, err
129		}
130		nonceSize := gcm.NonceSize()
131		if len(ciphertext) < nonceSize {
132			return nil, fmt.Errorf("keyfile too short")
133		}
134		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
135		return gcm.Open(nil, nonce, ct, nil)
136	}
137	
138	func decodeAESKey(hexStr string) ([]byte, error) {
139		if hexStr == "" {
140			return nil, fmt.Errorf("AES_MASTER_KEY is required")
141		}
142		aesKey, err := hex.DecodeString(hexStr)
143		if err != nil {
144			return nil, fmt.Errorf("AES_MASTER_KEY must be hex-encoded: %w", err)
145		}
146		if len(aesKey) != 32 {
147			return nil, fmt.Errorf("AES_MASTER_KEY must be 32 bytes (64 hex chars), got %d bytes", len(aesKey))
148		}
149		return aesKey, nil
150	}
