20	func main() {
21		if len(os.Args) < 2 {
22			fmt.Fprintf(os.Stderr, "Usage:\n")
23			fmt.Fprintf(os.Stderr, "  keyfile-tool encrypt <secrets.json> <output.enc> <passphrase>\n")
24			fmt.Fprintf(os.Stderr, "  keyfile-tool decrypt <input.enc> <passphrase>\n")
25			os.Exit(1)
26		}
27	
28		switch os.Args[1] {
29		case "encrypt":
30			if len(os.Args) != 5 {
31				fmt.Fprintf(os.Stderr, "Usage: keyfile-tool encrypt <secrets.json> <output.enc> <passphrase>\n")
32				os.Exit(1)
33			}
34			if err := encryptCmd(os.Args[2], os.Args[3], os.Args[4]); err != nil {
35				fmt.Fprintf(os.Stderr, "error: %v\n", err)
36				os.Exit(1)
37			}
38		case "decrypt":
39			if len(os.Args) != 4 {
40				fmt.Fprintf(os.Stderr, "Usage: keyfile-tool decrypt <input.enc> <passphrase>\n")
41				os.Exit(1)
42			}
43			if err := decryptCmd(os.Args[2], os.Args[3]); err != nil {
44				fmt.Fprintf(os.Stderr, "error: %v\n", err)
45				os.Exit(1)
46			}
47		default:
48			fmt.Fprintf(os.Stderr, "unknown command: %s\n", os.Args[1])
49			os.Exit(1)
50		}
51	}
