53	func encryptCmd(inputPath, outputPath, passphrase string) error {
54		plaintext, err := os.ReadFile(inputPath)
55		if err != nil {
56			return fmt.Errorf("read %s: %w", inputPath, err)
57		}
58	
59		// Validate JSON structure
60		var secrets secretsFile
61		if err := json.Unmarshal(plaintext, &secrets); err != nil {
62			return fmt.Errorf("invalid JSON: %w", err)
63		}
64		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
65			return fmt.Errorf("secrets file must contain database_url, jwt_signing_key, and aes_master_key")
66		}
67	
68		ciphertext, err := encryptKeyfile(plaintext, passphrase)
69		if err != nil {
70			return fmt.Errorf("encrypt: %w", err)
71		}
72	
73		if err := os.WriteFile(outputPath, ciphertext, 0600); err != nil {
74			return fmt.Errorf("write %s: %w", outputPath, err)
75		}
76	
77		fmt.Printf("Encrypted keyfile written to %s (mode 0600)\n", outputPath)
78		return nil
79	}
