81	func decryptCmd(inputPath, passphrase string) error {
82		ciphertext, err := os.ReadFile(inputPath)
83		if err != nil {
84			return fmt.Errorf("read %s: %w", inputPath, err)
85		}
86	
87		plaintext, err := decryptKeyfile(ciphertext, passphrase)
88		if err != nil {
89			return fmt.Errorf("decrypt: %w", err)
90		}
91	
92		// Pretty-print the JSON
93		var raw json.RawMessage
94		if err := json.Unmarshal(plaintext, &raw); err != nil {
95			os.Stdout.Write(plaintext)
96			return nil
97		}
98		pretty, _ := json.MarshalIndent(raw, "", "  ")
99		os.Stdout.Write(pretty)
100		fmt.Println()
101		return nil
102	}
103	
104	func encryptKeyfile(plaintext []byte, passphrase string) ([]byte, error) {
105		key := sha256.Sum256([]byte(passphrase))
106		block, err := aes.NewCipher(key[:])
107		if err != nil {
108			return nil, err
109		}
110		gcm, err := cipher.NewGCM(block)
111		if err != nil {
112			return nil, err
113		}
114		nonce := make([]byte, gcm.NonceSize())
115		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
116			return nil, err
117		}
118		return gcm.Seal(nonce, nonce, plaintext, nil), nil
119	}
120	
121	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
122		key := sha256.Sum256([]byte(passphrase))
123		block, err := aes.NewCipher(key[:])
124		if err != nil {
125			return nil, err
126		}
127		gcm, err := cipher.NewGCM(block)
128		if err != nil {
129			return nil, err
130		}
131		nonceSize := gcm.NonceSize()
132		if len(ciphertext) < nonceSize {
133			return nil, fmt.Errorf("keyfile too short")
134		}
135		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
136		return gcm.Open(nil, nonce, ct, nil)
137	}
