111	// GetByID with object-level authorization: only buyer or seller of the order can view it.
112	func (s *OrderService) GetByID(ctx context.Context, id uuid.UUID, actorID uuid.UUID) (*model.Order, error) {
113		order, err := s.orderStore.GetByID(ctx, id)
114		if err != nil {
115			return nil, err
116		}
117		if order == nil {
118			return nil, dto.ErrNotFound
119		}
120		if order.BuyerID != actorID && order.SellerID != actorID {
121			return nil, dto.ErrForbidden
122		}
123		return order, nil
124	}
125	
126	// TransitionStatus with object-level authorization.
127	// Confirm/Process/Complete: only the seller of THIS order.
128	// Cancel: only the buyer or seller of THIS order.
129	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
130		order, err := s.orderStore.GetByID(ctx, orderID)
131		if err != nil {
132			return nil, err
133		}
134		if order == nil {
135			return nil, dto.ErrNotFound
136		}
137	
138		// Object-level authorization
139		switch targetStatus {
140		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
141			if order.SellerID != actorID {
142				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
143			}
144		case model.OrderStatusCancelled:
145			if order.BuyerID != actorID && order.SellerID != actorID {
146				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
147			}
148		}
149	
150		if !order.Status.CanTransitionTo(targetStatus) {
151			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
152		}
153	
154		if targetStatus == model.OrderStatusCancelled {
155			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
156				return nil, fmt.Errorf("cancel order: %w", err)
157			}
158			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
159		} else {
160			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
161				return nil, fmt.Errorf("update status: %w", err)
162			}
163		}
164	
165		transition := &model.OrderStateTransition{
166			OrderID:    orderID,
167			FromStatus: order.Status,
168			ToStatus:   targetStatus,
169			ActorID:    actorID,
170			Reason:     reason,
171		}
172		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
173			return nil, fmt.Errorf("record transition: %w", err)
174		}
175	
176		// On completion, record an immutable transaction history entry for the
177		// collectible, representing the ownership transfer from seller to buyer.
178		if targetStatus == model.OrderStatusCompleted {
179			s.recordOwnershipTransfer(ctx, order)
180		}
181	
182		s.sendOrderNotification(ctx, order, targetStatus, reason)
183	
184		order.Status = targetStatus
185		return order, nil
186	}
187	
188	func (s *OrderService) sendOrderNotification(ctx context.Context, order *model.Order, status model.OrderStatus, reason string) {
189		if s.notifService == nil {
190			return
191		}
192	
193		slugMap := map[model.OrderStatus]string{
194			model.OrderStatusConfirmed:  "order_confirmed",
195			model.OrderStatusProcessing: "order_processing",
196			model.OrderStatusCompleted:  "order_completed",
197			model.OrderStatusCancelled:  "order_cancelled",
198		}
199	
200		slug, ok := slugMap[status]
201		if !ok {
202			return
203		}
204	
205		params := map[string]string{
206			"OrderID": order.ID.String(),
207			"Reason":  reason,
208		}
209		paramsJSON, _ := json.Marshal(params)
210	
211		go func() {
212			_ = s.notifService.Send(context.Background(), order.BuyerID, slug, paramsJSON)
213		}()
214	}
215	
216	// recordOwnershipTransfer appends an immutable record to collectible_tx_history
217	// when an order completes. The record captures the seller→buyer transfer using
218	// the collectible's on-chain identity. This is best-effort: a failure here does
219	// not roll back the order completion.
220	func (s *OrderService) recordOwnershipTransfer(ctx context.Context, order *model.Order) {
221		collectible, err := s.collectibleStore.GetByID(ctx, order.CollectibleID)
222		if err != nil || collectible == nil {
223			return
224		}
225	
226		fromAddr := collectible.ContractAddress
227		if fromAddr == "" {
228			fromAddr = order.SellerID.String()
229		}
230		toAddr := order.BuyerID.String()
231	
232		txHash := fmt.Sprintf("order:%s", order.ID.String())
233		blockNumber := order.PriceSnapshotCents // deterministic, non-zero value
234	
235		entry := &model.CollectibleTxHistory{
236			CollectibleID: order.CollectibleID,
237			TxHash:        txHash,
238			FromAddress:   fromAddr,
239			ToAddress:     toAddr,
240			BlockNumber:   blockNumber,
241			Timestamp:     time.Now(),
242		}
243	
244		// Best-effort: do not fail the order on tx history write failure.
245		_ = s.collectibleStore.RecordTxHistory(ctx, entry)
246	}
