14	func AnomalyDetectorJob(orderStore *store.OrderStore, analyticsStore *store.AnalyticsStore, logger *zap.Logger) Job {
15		return Job{
16			Name:     "anomaly_detector",
17			Interval: 5 * time.Minute,
18			Fn: func(ctx context.Context) error {
19				// Rule 1: More than 6 cancellations in 24 hours
20				if err := detectExcessiveCancellations(ctx, orderStore, analyticsStore, logger); err != nil {
21					logger.Error("excessive cancellations check failed", zap.Error(err))
22				}
23	
24				// Rule 2: More than 10 failed checkout attempts in 1 hour
25				if err := detectCheckoutFailures(ctx, analyticsStore, logger); err != nil {
26					logger.Error("checkout failures check failed", zap.Error(err))
27				}
28	
29				return nil
30			},
31		}
32	}
