20	func main() {
21		if len(os.Args) < 2 {
22			fmt.Fprintf(os.Stderr, "Usage:\n")
23			fmt.Fprintf(os.Stderr, "  keyfile-tool encrypt <secrets.json> <output.enc> <passphrase>\n")
24			fmt.Fprintf(os.Stderr, "  keyfile-tool decrypt <input.enc> <passphrase>\n")
25			os.Exit(1)
26		}
27	
28		switch os.Args[1] {
29		case "encrypt":
30			if len(os.Args) != 5 {
31				fmt.Fprintf(os.Stderr, "Usage: keyfile-tool encrypt <secrets.json> <output.enc> <passphrase>\n")
32				os.Exit(1)
33			}
34			if err := encryptCmd(os.Args[2], os.Args[3], os.Args[4]); err != nil {
35				fmt.Fprintf(os.Stderr, "error: %v\n", err)
36				os.Exit(1)
37			}
38		case "decrypt":
39			if len(os.Args) != 4 {
40				fmt.Fprintf(os.Stderr, "Usage: keyfile-tool decrypt <input.enc> <passphrase>\n")
41				os.Exit(1)
42			}
43			if err := decryptCmd(os.Args[2], os.Args[3]); err != nil {
44				fmt.Fprintf(os.Stderr, "error: %v\n", err)
45				os.Exit(1)
46			}
47		default:
48			fmt.Fprintf(os.Stderr, "unknown command: %s\n", os.Args[1])
49			os.Exit(1)
50		}
51	}
52	
53	func encryptCmd(inputPath, outputPath, passphrase string) error {
54		plaintext, err := os.ReadFile(inputPath)
55		if err != nil {
56			return fmt.Errorf("read %s: %w", inputPath, err)
57		}
58	
59		// Validate JSON structure
60		var secrets secretsFile
61		if err := json.Unmarshal(plaintext, &secrets); err != nil {
62			return fmt.Errorf("invalid JSON: %w", err)
63		}
64		if secrets.DatabaseURL == "" || secrets.JWTSigningKey == "" || secrets.AESMasterKey == "" {
65			return fmt.Errorf("secrets file must contain database_url, jwt_signing_key, and aes_master_key")
66		}
67	
68		ciphertext, err := encryptKeyfile(plaintext, passphrase)
69		if err != nil {
70			return fmt.Errorf("encrypt: %w", err)
71		}
72	
73		if err := os.WriteFile(outputPath, ciphertext, 0600); err != nil {
74			return fmt.Errorf("write %s: %w", outputPath, err)
75		}
76	
77		fmt.Printf("Encrypted keyfile written to %s (mode 0600)\n", outputPath)
78		return nil
79	}
80	
81	func decryptCmd(inputPath, passphrase string) error {
82		ciphertext, err := os.ReadFile(inputPath)
83		if err != nil {
84			return fmt.Errorf("read %s: %w", inputPath, err)
85		}
86	
87		plaintext, err := decryptKeyfile(ciphertext, passphrase)
88		if err != nil {
89			return fmt.Errorf("decrypt: %w", err)
90		}
91	
92		// Pretty-print the JSON
93		var raw json.RawMessage
94		if err := json.Unmarshal(plaintext, &raw); err != nil {
95			os.Stdout.Write(plaintext)
96			return nil
97		}
98		pretty, _ := json.MarshalIndent(raw, "", "  ")
99		os.Stdout.Write(pretty)
100		fmt.Println()
101		return nil
102	}
103	
104	func encryptKeyfile(plaintext []byte, passphrase string) ([]byte, error) {
105		key := sha256.Sum256([]byte(passphrase))
106		block, err := aes.NewCipher(key[:])
107		if err != nil {
108			return nil, err
109		}
110		gcm, err := cipher.NewGCM(block)
111		if err != nil {
112			return nil, err
113		}
114		nonce := make([]byte, gcm.NonceSize())
115		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
116			return nil, err
117		}
118		return gcm.Seal(nonce, nonce, plaintext, nil), nil
119	}
120	
121	func decryptKeyfile(ciphertext []byte, passphrase string) ([]byte, error) {
122		key := sha256.Sum256([]byte(passphrase))
123		block, err := aes.NewCipher(key[:])
124		if err != nil {
125			return nil, err
126		}
127		gcm, err := cipher.NewGCM(block)
128		if err != nil {
129			return nil, err
130		}
131		nonceSize := gcm.NonceSize()
132		if len(ciphertext) < nonceSize {
133			return nil, fmt.Errorf("keyfile too short")
134		}
135		nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
136		return gcm.Open(nil, nonce, ct, nil)
137	}
